// Load due scheduled actions + proactive reminder check + open loop check
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const CHAT_ID = '{{TELEGRAM_CHAT_ID}}';
const http = this.helpers.httpRequest;

async function pgrest(path) {
  const res = await http({
    method: 'GET',
    url: `${SUPABASE_URL}${path}`,
    headers: { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  return typeof res.body === 'string' ? JSON.parse(res.body) : res.body;
}

const userId = `telegram:${CHAT_ID}`;
const now = new Date();
const nowISO = now.toISOString();

// Load all context in parallel
const [dueActions, tasks, profiles, heartbeatCfg, mcpServers, openLoopCfg] = await Promise.all([
  pgrest(`/rest/v1/scheduled_actions?enabled=eq.true&next_run=lte.${nowISO}&order=next_run.asc`),
  pgrest(`/rest/v1/tasks?user_id=eq.${encodeURIComponent(userId)}&status=in.(pending,in_progress)&order=due_date.asc.nullslast,priority.desc`),
  pgrest(`/rest/v1/user_profiles?user_id=eq.${encodeURIComponent(userId)}&select=display_name,timezone,preferences`),
  pgrest('/rest/v1/heartbeat_config?check_name=eq.heartbeat&select=config,last_run,enabled'),
  pgrest('/rest/v1/mcp_registry?active=eq.true&select=server_name,mcp_url,description,tools'),
  pgrest('/rest/v1/heartbeat_config?check_name=eq.open_loop_check&select=config,last_run,enabled')
]);

const profile = (Array.isArray(profiles) && profiles.length > 0) ? profiles[0] : {};
const prefs = profile.preferences || {};
const tz = profile.timezone || 'Europe/Berlin';
const lang = prefs.language || 'German';

// Build MCP skills text for background checker
let mcpSkillsText = '';
if (Array.isArray(mcpServers) && mcpServers.length > 0) {
  mcpSkillsText = mcpServers.map(s => {
    const tools = Array.isArray(s.tools) ? s.tools.join(', ') : '';
    return `- ${s.server_name}: ${s.mcp_url} (tools: ${tools}) — ${s.description || ''}`;
  }).join('\n');
}

// Build result items from due scheduled actions
const items = [];

if (Array.isArray(dueActions)) {
  for (const action of dueActions) {
    items.push({
      json: {
        type: 'scheduled_action',
        actionId: action.id,
        message: action.instruction,
        chat_id: action.chat_id,
        user_id: action.user_id,
        source: 'scheduled_action',
        schedule: action.schedule,
        timezone: action.timezone || tz,
        run_count: action.run_count || 0,
        max_runs: action.max_runs,
        name: action.name,
        notify_mode: action.notify_mode || 'always',
        last_run: action.last_run || null,
        mcp_skills: mcpSkillsText,
        language: lang
      }
    });
  }
}

// Proactive reminder check (existing logic — kept as synthetic item)
const hbEnabled = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0) ? heartbeatCfg[0].enabled : false;
const hbLastRun = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0 && heartbeatCfg[0].last_run) ? new Date(heartbeatCfg[0].last_run) : null;
const hbMinInterval = (Array.isArray(heartbeatCfg) && heartbeatCfg.length > 0 && heartbeatCfg[0].config) ? (heartbeatCfg[0].config.min_interval_hours || 2) : 2;

if (hbEnabled) {
  const hoursSinceLastRun = hbLastRun ? (now.getTime() - hbLastRun.getTime()) / (1000 * 60 * 60) : 999;
  if (hoursSinceLastRun >= hbMinInterval) {
    const taskList = Array.isArray(tasks) ? tasks : [];
    const overdue = taskList.filter(t => t.due_date && new Date(t.due_date) < now);
    const urgentCutoff = new Date(now.getTime() + 24 * 60 * 60 * 1000);
    const urgent = taskList.filter(t => t.priority === 'urgent' && (!t.due_date || new Date(t.due_date) <= urgentCutoff));

    if (overdue.length > 0 || urgent.length > 0) {
      let instruction = `You are proactively checking in with the user. Respond in ${lang}. Send a brief, helpful reminder (1-3 sentences) about these items:\n`;
      if (overdue.length > 0) {
        instruction += `\nOverdue tasks:\n${overdue.map(t => `- ${t.title} (due: ${t.due_date}, priority: ${t.priority})`).join('\n')}`;
      }
      if (urgent.length > 0) {
        instruction += `\nUrgent tasks:\n${urgent.map(t => `- ${t.title}`).join('\n')}`;
      }
      instruction += `\n\nBe helpful, not annoying. If nothing seems worth messaging about, just skip this.`;

      items.push({
        json: {
          type: 'proactive_reminder',
          heartbeat_check_name: 'heartbeat',
          actionId: null,
          message: instruction,
          chat_id: CHAT_ID,
          user_id: userId,
          source: 'scheduled_action',
          notify_mode: 'always'
        }
      });
    }
  }
}

// NEW: Open Loop check (every ~24h, configurable). Asks the user about old unfinished intentions.
const olCfg = (Array.isArray(openLoopCfg) && openLoopCfg.length > 0) ? openLoopCfg[0] : null;
const olEnabled = olCfg ? olCfg.enabled : false;
const olLastRun = (olCfg && olCfg.last_run) ? new Date(olCfg.last_run) : null;
const olMinInterval = (olCfg && olCfg.config) ? (olCfg.config.min_interval_hours || 24) : 24;
const olMinAgeDays = (olCfg && olCfg.config) ? (olCfg.config.min_age_days || 3) : 3;

if (olEnabled) {
  const hoursSinceOL = olLastRun ? (now.getTime() - olLastRun.getTime()) / (1000 * 60 * 60) : 999;
  if (hoursSinceOL >= olMinInterval) {
    const ageCutoff = new Date(now.getTime() - olMinAgeDays * 24 * 60 * 60 * 1000).toISOString();
    const openLoops = await pgrest(`/rest/v1/memory_long?category=eq.open_loop&created_at=lt.${ageCutoff}&or=(expires_at.is.null,expires_at.gt.${nowISO})&select=id,content,importance,created_at,expires_at,metadata&order=importance.desc,created_at.asc&limit=10`);
    // Filter out closed entries client-side (PostgREST jsonb-path filtering is awkward across versions)
    const active = (Array.isArray(openLoops) ? openLoops : []).filter(ol => {
      const m = ol.metadata || {};
      return m.closed !== true && m.closed !== 'true';
    }).slice(0, 3);

    if (active.length > 0) {
      const lines = active.map(ol => {
        const days = Math.max(1, Math.floor((now.getTime() - new Date(ol.created_at).getTime()) / (1000 * 60 * 60 * 24)));
        return `- (id ${ol.id}, vor ${days} Tagen) ${ol.content}`;
      }).join('\n');

      const instruction = `Du fragst proaktiv beim User nach alten offenen Vorhaben. Antworte auf ${lang}. Sende EINE kurze, freundliche Nachricht (1-3 Sätze), die EINEN oder mehrere der folgenden offenen Punkte aufgreift. Sei nicht nervig — wenn ein Punkt zu trivial wirkt, lass ihn aus. Wenn alle Punkte trivial wirken, antworte nur mit dem Text [SKIP] und nichts anderem.\n\nWenn der User in seiner Antwort bestätigt, dass etwas erledigt/verworfen wurde, nutze memory_update auf die jeweilige id und setze metadata.closed=true (siehe Memory-Behavior-Regeln zu open_loop).\n\nOffene Vorhaben:\n${lines}`;

      items.push({
        json: {
          type: 'proactive_reminder',
          heartbeat_check_name: 'open_loop_check',
          actionId: null,
          message: instruction,
          chat_id: CHAT_ID,
          user_id: userId,
          source: 'scheduled_action',
          notify_mode: 'always'
        }
      });
    }
  }
}

if (items.length === 0) {
  return [{ json: { type: 'no_action' } }];
}

return items;

// Merge checker result with original action data for routing + update
const checkerResult = $input.first().json;
const actionData = $('Route by Notify Mode').first().json;

return [{
  json: {
    ...actionData,
    notify: checkerResult.notify || false,
    checkerMessage: checkerResult.message || ''
  }
}];

// Update scheduled action: last_run, run_count, next_run
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const http = this.helpers.httpRequest;

// Get the action data — always original data from Should Notify
// (Send Telegram is a dead-end, doesn't feed into Update Action)
const item = $input.first().json;
const now = new Date();

// Proactive reminder: update heartbeat_config (configurable check_name to support multiple proactive triggers)
if (item.type === 'proactive_reminder') {
  const checkName = item.heartbeat_check_name || 'heartbeat';
  await http({
    method: 'PATCH',
    url: `${SUPABASE_URL}/rest/v1/heartbeat_config?check_name=eq.${checkName}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: { last_run: now.toISOString() }
  });
  return [{ json: { status: 'updated', type: 'proactive_reminder', check: checkName } }];
}

// Scheduled action: compute next_run and update
const actionId = item.actionId;
const schedule = item.schedule;
const tz = item.timezone || 'Europe/Berlin';
const runCount = (item.run_count || 0) + 1;
const maxRuns = item.max_runs;

function computeNextRun(schedule, tz) {
  const now = new Date();

  if (schedule.type === 'interval') {
    // Subtract 30s buffer so the next heartbeat cycle reliably finds this action due
    return new Date(now.getTime() + (schedule.minutes || 60) * 60000 - 30000).toISOString();
  }

  if (schedule.type === 'daily') {
    const [h, m] = (schedule.time || '08:00').split(':').map(Number);
    const userNow = new Date(now.toLocaleString('en-US', { timeZone: tz }));
    const target = new Date(userNow);
    target.setHours(h, m, 0, 0);
    if (target <= userNow) {
      target.setDate(target.getDate() + 1);
    }
    const diffMs = target.getTime() - userNow.getTime();
    return new Date(now.getTime() + diffMs).toISOString();
  }

  if (schedule.type === 'weekly') {
    const [h, m] = (schedule.time || '09:00').split(':').map(Number);
    const days = schedule.days || [1];
    const userNow = new Date(now.toLocaleString('en-US', { timeZone: tz }));
    const jsDay = userNow.getDay();
    const currentDay = jsDay === 0 ? 7 : jsDay;
    const currentMinutes = userNow.getHours() * 60 + userNow.getMinutes();
    const targetMinutes = h * 60 + m;

    let minDaysAhead = 8;
    for (const d of days) {
      let ahead = d - currentDay;
      if (ahead < 0) ahead += 7;
      if (ahead === 0 && currentMinutes >= targetMinutes) ahead = 7;
      if (ahead < minDaysAhead) minDaysAhead = ahead;
    }

    const target = new Date(userNow);
    target.setDate(target.getDate() + minDaysAhead);
    target.setHours(h, m, 0, 0);
    const diffMs = target.getTime() - userNow.getTime();
    return new Date(now.getTime() + diffMs).toISOString();
  }

  return new Date(now.getTime() + 3600000).toISOString();
}

const nextRun = computeNextRun(schedule, tz);
const shouldDisable = maxRuns !== null && maxRuns !== undefined && runCount >= maxRuns;

await http({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/scheduled_actions?id=eq.${actionId}`,
  headers: {
    'apikey': SUPABASE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: {
    last_run: now.toISOString(),
    run_count: runCount,
    next_run: shouldDisable ? null : nextRun,
    enabled: !shouldDisable,
    updated_at: now.toISOString()
  }
});

return [{ json: { status: 'updated', actionId, runCount, nextRun: shouldDisable ? null : nextRun, disabled: shouldDisable } }];

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const BRIDGE_URL = 'http://file-bridge:3200';

// 1. Cleanup expired files on File Bridge
let bridgeResult = { cleaned: 0 };
try {
  bridgeResult = await helpers.httpRequest({
    method: 'DELETE',
    url: BRIDGE_URL + '/cleanup'
  });
} catch(e) {
  // File Bridge may not be running yet
}

// 2. Cleanup expired metadata in DB
let dbResult = null;
try {
  dbResult = await helpers.httpRequest({
    method: 'DELETE',
    url: SUPABASE_URL + '/rest/v1/file_refs?expires_at=lt.' + new Date().toISOString(),
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY
    }
  });
} catch(e) {}

return [{ json: { bridge_cleaned: bridgeResult.cleaned || 0, db_cleanup: 'done' } }];
